import './InlineAlert.scss';

import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { FC } from 'react';
import React from 'react';

import { classNames } from '../../helpers/classnames';
import { Icon } from '../Icon';
import { Typography } from '../Typography';
import type { InlineAlertProps } from './InlineAlert.types';

export const InlineAlert: FC<InlineAlertProps> = ({
	type = 'neutral',
	iconName = Icons.WarningCircled,
	children,
	className,
	...props
}) => (
	<div
		data-testid="InlineAlert"
		role="alert"
		aria-live={type === 'warning' ? 'assertive' : 'polite'}
		aria-atomic={true}
		className={classNames('dsb_alert', `dsb_alert__${type}`, className)}
		{...props}
	>
		<Icon className="dsb_alert-icon" iconName={iconName} size="medium" />

		{typeof children === 'string' ? (
			<Typography className="dsb_alert-content" variant="body3">
				{children}
			</Typography>
		) : (
			<div className="dsb_alert-custom-content">{children}</div>
		)}
	</div>
);
